COMMENT ON TABLE public.partners IS 'Partner information for Business Associates, Business Partners, and Channel Partners';
COMMENT ON TABLE public.customers IS 'Customer information with categorization and KYC details';
COMMENT ON TABLE public.employees IS 'Employee information with role-based access and performance metrics';
COMMENT ON TABLE public.vendors IS 'Vendor information for collection, auction, and service providers';
COMMENT ON TABLE public.loan_applications IS 'Loan application tracking and management';
COMMENT ON TABLE public.payouts IS 'Partner payout tracking and approval workflow';
COMMENT ON TABLE public.banners IS 'Banner management for different user roles';
COMMENT ON TABLE public.notifications IS 'User notification system';
COMMENT ON TABLE public.audit_logs IS 'Complete audit trail for all system activities';
COMMENT ON TABLE public.admin_permissions IS 'Granular admin permissions for module-level access control';
COMMENT ON TABLE public.properties IS 'Auction property management from collection vendors';
COMMENT ON TABLE public.incentives IS 'Employee incentive programs and rewards';
COMMENT ON TABLE public.contests IS 'Partner contest management and tracking';

